WITH p AS(SELECT 5690000000023241 pid,2026 yr,4 mon),a AS(SELECT t.*,CASE WHEN seq='8' THEN COALESCE((SELECT u_ywzb FROM v_qtzc_pm WHERE project_id=t.phid_pc),0) ELSE 0 END ywzb,CASE WHEN seq='8' THEN COALESCE((SELECT u_zrcbzb FROM v_qtzc_pm WHERE project_id=t.phid_pc),0) ELSE 0 END zrcbzb,CASE WHEN seq='8' THEN COALESCE((SELECT SUM(u_ewzb) FROM v_qtzc_pk WHERE phid_pc=t.phid_pc),0)+COALESCE((SELECT amt FROM v_qtzc_lxe WHERE phid_pc=t.phid_pc),0) WHEN seq='8.999' THEN COALESCE((SELECT amt FROM v_qtzc_lxe WHERE phid_pc=t.phid_pc),0) WHEN t.pid=-1 AND id<>-999 THEN COALESCE((SELECT u_ewzb FROM v_qtzc_pk WHERE sub_cont_pack_id=t.id AND phid_pc=t.phid_pc),0) ELSE 0 END ewzb,CASE WHEN seq='8' THEN COALESCE((SELECT SUM(u_htje) FROM v_qtzc_pk WHERE phid_pc=t.phid_pc),0) WHEN t.pid=-1 AND id<>-999 THEN COALESCE((SELECT u_htje FROM v_qtzc_pk WHERE sub_cont_pack_id=t.id AND phid_pc=t.phid_pc),0) WHEN id>0 AND t.pid<>-1 THEN COALESCE((SELECT total_sum FROM v_qtzc_b WHERE cnt_m_phid=t.id AND phid_pc=t.phid_pc),0) ELSE 0 END htje,CASE WHEN seq='8' THEN COALESCE((SELECT SUM(kd) FROM v_qtzc_kdm x,p WHERE phid_pc=t.phid_pc AND x.yr=p.yr AND x.mon=p.mon),0)+COALESCE((SELECT amt FROM v_qtzc_lxm x,p WHERE phid_pc=t.phid_pc AND x.yr=p.yr AND x.mon=p.mon),0) WHEN seq='8.999' THEN COALESCE((SELECT amt FROM v_qtzc_lxm x,p WHERE phid_pc=t.phid_pc AND x.yr=p.yr AND x.mon=p.mon),0) WHEN t.pid=-1 AND id<>-999 THEN COALESCE((SELECT SUM(kd) FROM v_qtzc_kdm x,p WHERE sub_cont_pack_id=t.id AND phid_pc=t.phid_pc AND x.yr=p.yr AND x.mon=p.mon),0) ELSE COALESCE((SELECT kd FROM v_qtzc_kdm x,p WHERE contract_id=t.id AND phid_pc=t.phid_pc AND x.yr=p.yr AND x.mon=p.mon),0) END bykd,CASE WHEN seq='8' THEN COALESCE((SELECT SUM(kd) FROM v_qtzc_kdy x,p WHERE phid_pc=t.phid_pc AND x.yr=p.yr),0)+COALESCE((SELECT amt FROM v_qtzc_lxy x,p WHERE phid_pc=t.phid_pc AND x.yr=p.yr),0) WHEN seq='8.999' THEN COALESCE((SELECT amt FROM v_qtzc_lxy x,p WHERE phid_pc=t.phid_pc AND x.yr=p.yr),0) WHEN t.pid=-1 AND id<>-999 THEN COALESCE((SELECT SUM(kd) FROM v_qtzc_kdy x,p WHERE sub_cont_pack_id=t.id AND phid_pc=t.phid_pc AND x.yr=p.yr),0) ELSE COALESCE((SELECT kd FROM v_qtzc_kdy x,p WHERE contract_id=t.id AND phid_pc=t.phid_pc AND x.yr=p.yr),0) END bnljkd,CASE WHEN seq='8' THEN COALESCE((SELECT SUM(kd) FROM v_qtzc_kda WHERE phid_pc=t.phid_pc),0)+COALESCE((SELECT amt FROM v_qtzc_lxa WHERE phid_pc=t.phid_pc),0) WHEN seq='8.999' THEN COALESCE((SELECT amt FROM v_qtzc_lxa WHERE phid_pc=t.phid_pc),0) WHEN t.pid=-1 AND id<>-999 THEN COALESCE((SELECT SUM(kd) FROM v_qtzc_kda WHERE sub_cont_pack_id=t.id AND phid_pc=t.phid_pc),0) ELSE COALESCE((SELECT kd FROM v_qtzc_kda WHERE contract_id=t.id AND phid_pc=t.phid_pc),0) END kgljkd,CASE WHEN seq='8' THEN COALESCE((SELECT SUM(yf) FROM v_qtzc_kdm x,p WHERE phid_pc=t.phid_pc AND x.yr=p.yr AND x.mon=p.mon),0) WHEN seq='8.999' THEN 0 WHEN t.pid=-1 AND id<>-999 THEN COALESCE((SELECT SUM(yf) FROM v_qtzc_kdm x,p WHERE sub_cont_pack_id=t.id AND phid_pc=t.phid_pc AND x.yr=p.yr AND x.mon=p.mon),0) ELSE COALESCE((SELECT yf FROM v_qtzc_kdm x,p WHERE contract_id=t.id AND phid_pc=t.phid_pc AND x.yr=p.yr AND x.mon=p.mon),0) END byysgck,CASE WHEN seq='8' THEN COALESCE((SELECT SUM(yf) FROM v_qtzc_kda WHERE phid_pc=t.phid_pc),0) WHEN seq='8.999' THEN 0 WHEN t.pid=-1 AND id<>-999 THEN COALESCE((SELECT SUM(yf) FROM v_qtzc_kda WHERE sub_cont_pack_id=t.id AND phid_pc=t.phid_pc),0) ELSE COALESCE((SELECT yf FROM v_qtzc_kda WHERE contract_id=t.id AND phid_pc=t.phid_pc),0) END kgljysgck FROM v_qtzc_t t,p WHERE t.phid_pc=p.pid)SELECT phid_pc,id s_tree_id,pid s_tree_pid,seq s_tree_no,htbh u_htbh,name s_tree_name,ywzb,zrcbzb,ewzb,htje,htje yjjsz,bykd,bnljkd,kgljkd,byysgck,kgljysgck,0 byssgck,0 kgljssgck,'' htzt,(SELECT yr FROM p) tj_year,(SELECT mon FROM p) tj_mon FROM a ORDER BY CASE WHEN seq='8' THEN 1 WHEN seq='8.999' THEN 999 WHEN pid=-1 AND id<>-999 THEN 2 ELSE 3 END,seq;
